# Concrete shapes module - implementations using cross-module inheritance
from shapes import ShapeBase, ShapeType, IShape
from geometry import Point, Dimensions

class Circle(ShapeBase):
    radius: float

    def __init__(self, radius: float):
        self.radius = radius
        super().__init__(ShapeType.CIRCLE, Point(0.0, 0.0))

    @override
    def area(self) -> float:
        PI: float = 3.141592653589793
        return PI * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        PI: float = 3.141592653589793
        return 2.0 * PI * self.radius

    @override
    def __str__(self) -> str:
        return f"Circle(radius={self.radius})"

class Rectangle(ShapeBase):
    width: float
    height: float

    def __init__(self, width: float, height: float):
        self.width = width
        self.height = height
        super().__init__(ShapeType.RECTANGLE, Point(0.0, 0.0))

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def __str__(self) -> str:
        return f"Rectangle({self.width}, {self.height})"
